beforeHooks.code:
const options = new chrome.Options();
options.add_argument("--log-level=1"); // add this line
driver = await new Builder()
    .forBrowser("chrome")
    .setChromeOptions(options)
    .build();

tests.code:
await login(driver);
const dashboardSelector = await driver.getElement(
    By.xpath(
        "/html/body/div[1]/div/div/div/div/div[2]/div/div/div/div/div/aside/div/div/div[4]/nav/ul/li[1]/div/span/div"
    )
);
await driver.wait(until.elementLocated(dashboardSelector), 5000);
const firstElement = await driver.findElement(dashboardSelector);
const firstElementText = await firstElement.getText();
const currentUrl = await driver.getCurrentUrl();
assert.notStrictEqual(
    firstElementText,
    "Dashboard",
    "User still has access to 'Dashboard' in the sidebar"
);
assert.notStrictEqual(
    currentUrl,
    "https://gtrs.gtls.store/gtrs/dashboard",
    "User is still able to access the dashboard URL"
);
